from random_graph import generate_graph,show
import numpy as np

#SIR model simulation
def cascade(t=100, n=2,spread=0.15,budget=0,edges=None, infected=None, mode="SIR",displ=False):
    if edges is None:
        edges = {(0, 1), (1, 0)}
    else:
        edges = set(edges)

    if infected is None:
        infected = {0}
    
    suceptible={i for i in range(n)}
    for inf in infected:
        suceptible.remove(inf)

    safe=set()
    #initialize the infected edges
    risk_edges=set()
    for edge in edges:
        i=edge[0]
        if i in infected:
            risk_edges.add(edge)

    #Removing risk edges
    np.random.shuffle(list(risk_edges))
    risk_edges=set(list(risk_edges)[budget:])
    rem_edges= set(list(risk_edges)[:budget])
    for edge in rem_edges:
        edges.discard(edge)    
    
    #SIR model
    for time in range(t):
        #Stop criteria
        if len(risk_edges)<1:
            return time, [suceptible,infected,safe]
        if displ:show(n=n,edges=edges,sets=[suceptible,infected,safe])

        #Infection step
        if(mode=="SIR"):
            for inf_edge in risk_edges:
                (i, j) = inf_edge
                if j in suceptible:
                    if np.random.uniform(0,1)<=spread:
                        infected.add(j)
                    else:
                        safe.add(j)
                    suceptible.discard(j)

        if(mode=="SI"):
            for inf_edge in risk_edges:
                (i, j) = inf_edge
                if j in suceptible:
                    if np.random.uniform(0,1)<=spread:
                        infected.add(j)                   
                        suceptible.discard(j)

        
        #Update risk_edges
        risk_edges.clear()
        for edge in edges:
            (i,j)=edge
            if i in infected and j in suceptible :
                risk_edges.add(edge)
        # Remove edges
        np.random.shuffle(list(risk_edges))
        risk_edges=set(list(risk_edges)[budget:])
        rem_edges= set(list(risk_edges)[:budget])
        for edge in rem_edges:
            edges.discard(edge)    
        
    return t, [suceptible,infected,safe]



